import ldap

def search_user_by_username(ldap_server, base_dn, search_filter):
    try:
        # Initialize LDAP connection
        l = ldap.initialize(ldap_server)
        
        # Perform the search
        result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter)
        
        # Retrieve results
        results = []
        while True:
            result_type, result_data = l.result(result_id, 0)
            if (result_data == []):
                break
            else:
                if result_type == ldap.RES_SEARCH_ENTRY:
                    for entry in result_data:
                        results.append(entry[0])
        
        return results
    
    except ldap.LDAPError as e:
        print(f"LDAP Error: {e}")
        return []

